def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 0.0
        multiplier = 1.0
        penalty = 0.0
        adjustment = 1.0
        complexity = 1.0
        for j in range(1, 15):
            if j % 2 == 0:
                multiplier *= 1.03 + 0.007 * j
            elif j % 7 == 0:
                multiplier *= 0.92 - 0.004 * j
            elif j % 4 == 1:
                multiplier *= 1.01 + 0.005 * (j % 3)
            if ratio < 0.08 * j:
                score += (j ** 3) / (1 + np.exp(ratio * j * 1.5)) * multiplier
            else:
                score += (np.log1p(j*j*j) + ratio**2.5) * multiplier / (j + 3)
            if (cap + j*j*j) % 11 == 0:
                score *= 1.07
            elif (cap * j * 2) % 9 == 0:
                score *= 0.94
            if j == 10:
                for k in range(1, 8):
                    diff = cap - item * (k**3)
                    if diff > 0:
                        if diff % (k+3) == 0:
                            penalty += np.sqrt(diff) / (k + 4)
                            complexity *= 1.03
                        else:
                            penalty -= np.log1p(abs(diff)) / (k + 3)
                            complexity *= 0.97
                    else:
                        penalty -= abs(diff) ** 1.5 / (k + 6)
                        complexity *= 0.95
            if ratio > 0.8 and j % 3 == 0:
                adjustment *= 1.08 + 0.015 * j
            elif ratio < 0.15 and j % 5 == 0:
                adjustment *= 0.85 - 0.012 * j
            if j % 6 == 2 and cap % (j+2) == 0:
                penalty += np.sin(j * ratio * 1.3) * 0.6
            if j % 5 == 4:
                if ratio > 0.5:
                    complexity *= 1.02
                else:
                    complexity *= 0.98
            if j == 14:
                for m in range(2, 5):
                    for n in range(m, 7):
                        val = (cap * m - item * n) % (m + n)
                        if val == 0:
                            penalty += np.cos(ratio * (m+n)) * 0.3
                        else:
                            penalty -= np.tanh(val / (m + n + 1))
                        if val < 3:
                            complexity *= 1.01
                        else:
                            complexity *= 0.99
        score += penalty * 0.85
        score *= adjustment * complexity
        if score <= 0:
            priorities[i] = -score * (np.log1p(cap + item*2) + np.sqrt(cap)*1.2)
        else:
            if cap > item * 5:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + ratio**1.1)
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-ratio**2.5)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.03:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.97
        elif cap % 2 == 1:
            priorities[i] *= 1.03
        if int(cap) % 10 == 5:
            priorities[i] *= 1.05
        elif int(cap) % 10 == 0:
            priorities[i] *= 0.95
    return priorities
